/* Types */
/**  Agent 启动时读取的 LLM 配置（由 OmniPanel 写入 app_data_dir/acp-agent-config.json）。 */
export type AcpAgentConfigInput = {
	model: string,
	apiKey: string,
	baseUrl: string,
	apiStandard: string,
};

export type AcpPermissionOption = {
	optionId: string,
	name: string,
};

export type AcpStatus = {
	connected: boolean,
	agentName: string | null,
	executable: string | null,
};

export type AcpStreamEvent = { type: "content_delta"; text: string } | { type: "reasoning_delta"; text: string } | { type: "tool_call"; id: string; name: string; arguments: string } | { type: "tool_call_update"; id: string; status: string; result: string | null } | { type: "permission_request"; requestId: number | null; tool_call_id: string; title: string; raw_input: string; options: AcpPermissionOption[] } | { type: "done"; stop_reason: string } | { type: "error"; message: string };

/**  前端发起的动作请求。 */
export type ActionRequest = {
	id: string,
	/**  动作类型（terminal/docker/server/ssh/sql 等），决定分发到哪个 executor。 */
	kind: string,
	command?: string | null,
	resourceId?: string | null,
	envTag?: string | null,
	/**  工作目录（本地 shell 类执行可用）。 */
	cwd?: string | null,
};

/**  微信扫码登录二维码（GET /api/login/qrcode）。 */
export type AuthLoginQrcode = {
	loginId: string,
	scene: string,
	ticket: string,
	qrcodeUrl: string,
	expireInSec: number,
};

/**  微信扫码登录成功（SSE login 事件载荷）。 */
export type AuthLoginSuccess = {
	token: string,
	openid: string,
};

/**  本机设备身份（登录上报与「本机」标记共用）。 */
export type AuthDeviceIdentity = {
	deviceId: string,
	deviceName: string,
	osType: string,
};

/**  已授权设备列表条目。 */
export type AuthDevice = {
	id: number,
	deviceId: string,
	deviceName: string,
	osType: string,
	ip: string,
	lastLoginAt: string,
	userAgent: string,
	createdAt: string,
	updatedAt: string,
};

/**  当前用户资料（GET/PATCH /api/me）。 */
export type AuthUserProfile = {
	id: number,
	openid: string,
	nickname: string,
	avatarUrl: string,
	email: string,
};

